const express = require('express');
const app = express();

// Load plugins from configuration files or environment variables
const pluginConfig = {
  // Example configuration for a plugin that modifies requests
  requestPlugin: {
    enabled: true,
    code: `
      module.exports = function(req, res, next) {
        console.log('Request plugin running');
        next();
      }
    `
  },
  // Example configuration for a plugin that modifies responses
  responsePlugin: {
    enabled: true,
    code: `
      module.exports = function(req, res, next) {
        console.log('Response plugin running');
        next();
      }
    `
  },
  // Example configuration for a plugin that executes custom logic
  customPlugin: {
    enabled: true,
    code: `
      module.exports = function(req, res, next) {
        console.log('Custom plugin running');
        next();
      }
    `
  }
};

// Load plugins dynamically using eval() or require()
const loadPlugin = (pluginName) => {
  if (!pluginConfig[pluginName]) {
    return;
  }
  const pluginCode = pluginConfig[pluginName].code;
  try {
    // Use eval() to execute the plugin code
    const pluginModule = eval(pluginCode);
    // Call the plugin function with the request, response, and next functions as arguments
    pluginModule(req, res, next);
  } catch (err) {
    console.error('Error loading plugin', err);
  }
};

// Load plugins based on configuration
const loadPlugins = () => {
  Object.keys(pluginConfig).forEach((pluginName) => {
    if (pluginConfig[pluginName].enabled) {
      loadPlugin(pluginName);
    }
  });
};

// Middleware function to handle requests and responses
const middleware = (req, res, next) => {
  // Load plugins based on configuration
  loadPlugins();
  // Call the next middleware function in the chain
  next();
};

// Use the middleware function as a route handler
app.use(middleware);

// Start the server
const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Server started on port ${port}`);
});